type (
	// Filter is the interface that wraps the Where function
	// for filtering nodes in queries and mutations.
	Filter interface {
		// Where applies a filter on the executed query/mutation.
		Where(entql.P)
	}

	// The FilterFunc type is an adapter that allows the use of ordinary
	// functions as filters for query and mutation types.
	FilterFunc func(context.Context, Filter) error
)

// EvalQuery calls f(ctx, q) if the query implements the Filter interface, otherwise it is denied.
func (f FilterFunc) EvalQuery(ctx context.Context, q ent.Query) error {
	fr, err := queryFilter(q)
	if err != nil {
		return err
	}
	return f(ctx, fr)
}

// EvalMutation calls f(ctx, q) if the mutation implements the Filter interface, otherwise it is denied.
func (f FilterFunc) EvalMutation(ctx context.Context, m ent.Mutation) error {
	fr, err := mutationFilter(m)
	if err != nil {
		return err
	}
	return f(ctx, fr)
}

var _ QueryMutationRule = FilterFunc(nil)

func queryFilter(q ent.Query) (Filter, error) {
	switch q := q.(type) {
	case *ent.AgentLogQuery:
		return q.Filter(), nil
	case *ent.AuditLogQuery:
		return q.Filter(), nil
	case *ent.GlobalSettingQuery:
		return q.Filter(), nil
	case *ent.GroupQuery:
		return q.Filter(), nil
	case *ent.GroupMemberQuery:
		return q.Filter(), nil
	case *ent.HostQuery:
		return q.Filter(), nil
	case *ent.HostMACQuery:
		return q.Filter(), nil
	case *ent.ImageQuery:
		return q.Filter(), nil
	case *ent.ImageTypeQuery:
		return q.Filter(), nil
	case *ent.ImagingLogQuery:
		return q.Filter(), nil
	case *ent.InventoryQuery:
		return q.Filter(), nil
	case *ent.ModuleQuery:
		return q.Filter(), nil
	case *ent.ModuleStatusQuery:
		return q.Filter(), nil
	case *ent.MulticastSessionQuery:
		return q.Filter(), nil
	case *ent.OSTypeQuery:
		return q.Filter(), nil
	case *ent.PendingMACQuery:
		return q.Filter(), nil
	case *ent.PrinterQuery:
		return q.Filter(), nil
	case *ent.PrinterAssocQuery:
		return q.Filter(), nil
	case *ent.RefreshTokenQuery:
		return q.Filter(), nil
	case *ent.ScheduledTaskQuery:
		return q.Filter(), nil
	case *ent.SnapinQuery:
		return q.Filter(), nil
	case *ent.SnapinAssocQuery:
		return q.Filter(), nil
	case *ent.SnapinJobQuery:
		return q.Filter(), nil
	case *ent.SnapinTaskQuery:
		return q.Filter(), nil
	case *ent.StorageGroupQuery:
		return q.Filter(), nil
	case *ent.StorageNodeQuery:
		return q.Filter(), nil
	case *ent.TaskQuery:
		return q.Filter(), nil
	case *ent.UserQuery:
		return q.Filter(), nil
	default:
		return nil, Denyf("ent/privacy: unexpected query type %T for query filter", q)
	}
}

